struct BackgroundDemo: View {
    @Environment(\.overlayContainerManager) var manager
    @State var tapToDismiss = true
    var body: some View {
        ZStack {
            Color.clear
            VStack {
                VStack {
                    ForEach(backgrounds) { background in
                        Button(action: {
                            let viewConfiguration = BackgroundDemoViewConfiguration(
                                tapToDismiss: tapToDismiss,
                                backgroundStyle: background.background
                            )
                            let size = CGSize(width: 300, height: 400)
                            let view = BlockView(size: size, text: background.description, opacity: 1, allowDismiss: false)
                            manager.show(view: view, in: "backgroundContainer", using: viewConfiguration)
                        }, label: {
                            Text(background.description)
                                .frame(width: 250)
                        })
                        .buttonStyle(.bordered)
                    }
                    Toggle("TapToDismiss", isOn: $tapToDismiss)
                        .toggleStyle(.automatic)
                        .padding(.vertical, 20)
                        .padding(.horizontal, 50)
                }
                .padding(.top, 50)
                Spacer()
                VStack {
                    Text("ViewBackgroundDescription")
                        .padding(.horizontal, 30)
                }
                .padding(.bottom, 300)
            }
        }
        .background(LinearGradient(colors: [.blue, .cyan, .green], startPoint: .top, endPoint: .bottom).opacity(0.5))
        .overlayContainer("backgroundContainer", containerConfiguration: BackgroundContainerConfiguration())
        .edgesIgnoringSafeArea(.bottom)
        .navigationTitle("ViewBackgroundLabel")
        #if !os(macOS)
            .navigationBarTitleDisplayMode(.inline)
        #endif
    }
}

struct BindDemo: View {
    @Environment(\.overlayContainerManager) var manager
    @State var showA = false
    @State var showB = false
    let container = "bindValueContainer"
    var body: some View {
        ZStack {
            LinearGradient(colors: [.blue, .cyan, .green], startPoint: .top, endPoint: .bottom).opacity(0.5)
            VStack {
                VStack {
                    buttonGroup(view: "A", isPresented: $showA)
                    buttonGroup(view: "B", isPresented: $showB)
                }
                .padding(.horizontal, 30)
                .padding(.top, 100)
                .buttonStyle(.bordered)
                Spacer()
                VStack {
                    Text("BindValueDescription")
                        .padding(.horizontal, 30)
                }
                .padding(.bottom, 300)
            }
        }
        .overlayContainer(container, containerConfiguration: BindDemoContainerConfiguration())
        .containerView(in: container, configuration: configA, isPresented: $showA, content: viewA)
        .containerView(in: container, configuration: configB, isPresented: $showB, content: viewB)
        .edgesIgnoringSafeArea(.bottom)
        .navigationTitle("BindValueLabel")
        #if !os(macOS)
            .navigationBarTitleDisplayMode(.inline)
        #endif
    }
    @ViewBuilder
    func buttonGroup(view: String, isPresented: Binding<Bool>) -> some View {
        GroupBox {
            VStack {
                Button {
                    isPresented.wrappedValue.toggle()
                } label: {
                    if isPresented.wrappedValue {
                        Text("Dismiss \(view)")
                    } else {
                        Text("Show \(view)")
                    }
                }
                .textCase(.uppercase)
                Text("IsPresentedStatus \(view) \(isPresented.wrappedValue ? "True" : "False")")
            }
            .frame(width: 300)
        }
    }
    @ViewBuilder
    var viewA: some View {
        let size = CGSize(width: 200, height: 250)
        BlockView(size: size, text: "View \("A")", opacity: 0.6)
    }
    var configA: ContainerViewConfigurationProtocol {
        BindDemoViewConfiguration(alignment: .bottomLeading, transition: .move(edge: .leading))
    }
    @ViewBuilder
    var viewB: some View {
        let size = CGSize(width: 200, height: 250)
        BlockView(size: size, text: "View \("B")", opacity: 0.6)
    }
    var configB: ContainerViewConfigurationProtocol {
        BindDemoViewConfiguration(alignment: .bottomTrailing, transition: .move(edge: .trailing))
    }
}

struct ControllableAnimationDemo: View {
    @Environment(\.overlayContainerManager) var manager
    let container = "animationContainer"
    var body: some View {
        ZStack {
            LinearGradient(colors: [.blue, .cyan, .green], startPoint: .top, endPoint: .bottom).opacity(0.5)
            VStack {
                VStack {
                    Button {
                        let view = BlockView(size: .init(width: 300, height: 80), text: "ShowWithAnimation", opacity: 0.8)
                        manager.show(view: view, in: container, using: AnimatedViewConfiguration())
                    } label: {
                        Text("ShowWithAnimation")
                            .frame(width: 300)
                    }
                    Button {
                        let view = BlockView(size: .init(width: 300, height: 80), text: "ShowWithoutAnimation", opacity: 0.8)
                        manager.show(view: view, in: container, using: AnimatedViewConfiguration(), animated: false)
                    } label: {
                        Text("ShowWithoutAnimation")
                            .frame(width: 300)
                    }
                    Button {
                        manager.dismissAllView(in: [container], animated: true)
                    } label: {
                        Text("DismissWithoutAnimation")
                            .frame(width: 300)
                    }
                    Button {
                        manager.dismissAllView(in: [container], animated: false)
                    } label: {
                        Text("DismissWithoutAnimation")
                            .frame(width: 300)
                    }
                }
                .padding(.horizontal, 30)
                .padding(.top, 100)
                .buttonStyle(.bordered)
                Spacer()
                VStack {
                    Text("ControllableAnimationDescription")
                        .padding(.horizontal, 30)
                }
                .padding(.bottom, 300)
            }
        }
        .overlayContainer(container, containerConfiguration: AnimatedContainerConfiguration())
        .edgesIgnoringSafeArea(.bottom)
        .navigationTitle("ControllableAnimationLabel")
        #if !os(macOS)
            .navigationBarTitleDisplayMode(.inline)
        #endif
    }
}

struct CustomMenuDemo: View {
    @State var transitionType = 0
    @Namespace var menu
    let container = "menuContainer"
    let button1 = "button1"
    let button2 = "button2"
    @State var showButton1 = false
    @State var showButton2 = false
    var body: some View {
        ZStack {
            Color(backgroundColorOfZStack)
            VStack {
                Picker("", selection: $transitionType) {
                    Text("Transition1")
                        .tag(0)
                    Text("Transition2")
                        .tag(1)
                }
                .pickerStyle(.segmented)
                .padding()
                HStack {
                    Button {
                        showButton1.toggle()
                    } label: {
                        Text("PopMenu")
                            .textCase(.uppercase)
                    }
                    .buttonStyle(.bordered)
                    .matchedGeometryEffect(id: button1, in: menu, properties: .position, anchor: .bottom, isSource: true)
                    .containerView(
                        in: container,
                        isPresented: $showButton1,
                        content: MenuView(
                            isPresented: $showButton1,
                            transitionType: transitionType,
                            namespace: menu,
                            id: button1,
                            anchor: .top
                        )
                    )
                }
                Spacer()
                Text("CustomMenuDescription")
                    .padding(.horizontal, 30)
                    .padding(.bottom, 30)
            }
            .frame(maxHeight: 300)
            #if targetEnvironment(macCatalyst) || !os(macOS)
                .toolbar {
                    Button {
                        showButton2.toggle()
                    } label: {
                        Image(systemName: "pencil.circle.fill")
                    }
                    .matchedGeometryEffect(id: button2, in: menu, properties: .position, anchor: .bottomTrailing, isSource: true)
                    .containerView(
                        in: container,
                        isPresented: $showButton2,
                        content: MenuView(
                            isPresented: $showButton2,
                            transitionType: transitionType,
                            namespace: menu,
                            id: button2,
                            anchor: .topTrailing
                        )
                    )
                }
            #endif
        }
        .edgesIgnoringSafeArea(.bottom)
        .navigationTitle("CustomMenuLabel")
        .overlayContainer(container, containerConfiguration: MenuContainerConfiguration())
        #if !os(macOS)
            .navigationBarTitleDisplayMode(.inline)
        #endif
    }
}

struct MenuView: View {
    @Binding var isPresented: Bool
    let transitionType: Int
    let namespace: Namespace.ID
    let id: String
    let anchor: UnitPoint
    var dismiss: () -> Void {
        { isPresented = false }
    }
    let icons = ["cloud.fill", "cloud.drizzle.fill", "cloud.fog.fill", "cloud.bolt.fill", "smoke.fill"]
    var count: Int { icons.count }
    var body: some View {
        VStack {
            ForEach(0..<count, id: \.self) { i in
                Button {
                    print("do action of item: \(i)")
                    dismiss()
                } label: {
                    HStack {
                        Text("Item \(i)")
                        Spacer()
                        Image(systemName: icons[i])
                    }
                    .padding(.horizontal, 20)
                    .contentShape(Rectangle())
                }
                if i < (count - 1) {
                    Divider()
                } else {
                    Divider()
                        .hidden()
                }
            }
            .foregroundColor(.primary)
            #if os(macOS) && !targetEnvironment(macCatalyst)
                .buttonStyle(PlainButtonStyle())
            #endif
        }
        .padding(.top, 10)
        .frame(width: 150)
        .background(Color.white)
        .padding(.top, 10)
        .matchedGeometryEffect(id: id, in: namespace, properties: .position, anchor: anchor, isSource: false)
    }
}

struct DismissGestureDemo: View {
    @Environment(\.overlayContainerManager) var manager
    var body: some View {
        ZStack {
            Color(backgroundColorOfZStack)
            VStack {
                VStack {
                    ForEach(gestures) { dismissGesture in
                        Button(action: {
                            let configuration = GestureViewConfiguration(dismissGesture: dismissGesture.gesture)
                            let view = BlockView(
                                size: .init(width: 200, height: 80),
                                text: dismissGesture.description,
                                opacity: 0.7,
                                allowDismiss: false
                            )
                            manager.show(view: view, in: "gestureContainer", using: configuration)
                        }, label: {
                            Text(dismissGesture.description)
                                .frame(width: 200)
                        })
                    }
                }
                .padding(.top, 50)
                .buttonStyle(.bordered)
                .controlSize(.large)
                ViewContainer("gestureContainer", configuration: GestureContainer())
                VStack {
                    Text("DismissGestureDescription")
                }
                .padding(.init(top: 0, leading: 20, bottom: 40, trailing: 20))
            }
        }
        .edgesIgnoringSafeArea(.bottom)
        .navigationTitle("DismissGestureLabel")
        #if !os(macOS)
            .navigationBarTitleDisplayMode(.inline)
        #endif
    }
}
